  function env(g,t,a,peak,dur,floor){ g.gain.setValueAtTime(0.0001,t); g.gain.linearRampToValueAtTime(peak,t+a); g.gain.exponentialRampToValueAtTime(floor||0.0008,t+dur); }
  function burst(a,t,dur,peak,attack,hp,lp,q){ const n=Math.max(1,Math.floor(a.sampleRate*dur)); const buf=a.createBuffer(1,n,a.sampleRate),d=buf.getChannelData(0); for(let i=0;i<n;i++) d[i]=Math.random()*2-1; const s=a.createBufferSource(); s.buffer=buf; const g=a.createGain(); env(g,t,attack,peak,dur); let node=s; if(hp){ const f=a.createBiquadFilter(); f.type='highpass'; f.frequency.value=hp; if(q)f.Q.value=q; node.connect(f); node=f; } if(lp){ const f2=a.createBiquadFilter(); f2.type='lowpass'; f2.frequency.value=lp; node.connect(f2); node=f2; } node.connect(g).connect(a.destination); s.start(t); s.stop(t+dur); }

