function startBGM(){ const a=ensure(); if(!a||bgm)return;
  const master=a.createGain(); master.gain.setValueAtTime(0.0001,a.currentTime); master.gain.linearRampToValueAtTime(0.50,a.currentTime+3); master.connect(a.destination);
  const o1=a.createOscillator(),o2=a.createOscillator(),lp=a.createBiquadFilter(),dg=a.createGain(); o1.type='sawtooth'; o2.type='sawtooth'; o1.frequency.value=55; o2.frequency.value=55.5; lp.type='lowpass'; lp.frequency.value=210; dg.gain.value=0.15; o1.connect(lp); o2.connect(lp); lp.connect(dg); dg.connect(master); o1.start(); o2.start();
  const padG=a.createGain(); padG.gain.value=0.0; padG.connect(master); padG.gain.linearRampToValueAtTime(0.085,a.currentTime+5);
  const padFreqs=[110,130.81,164.81,220], padOscs=[]; padFreqs.forEach((f,i)=>{ const po=a.createOscillator(),pg=a.createGain(); po.type=i<2?'sawtooth':'triangle'; po.frequency.value=f*(1+(i?0.003:0)); pg.gain.value=[0.5,0.32,0.3,0.22][i]; po.connect(pg).connect(padG); po.start(); padOscs.push(po); });
  const lfo=a.createOscillator(),lfoG=a.createGain(); lfo.type='sine'; lfo.frequency.value=0.12; lfoG.gain.value=0.025; lfo.connect(lfoG).connect(padG.gain); lfo.start();
  const lfo2=a.createOscillator(),lfo2G=a.createGain(); lfo2.type='sine'; lfo2.frequency.value=5.5; lfo2G.gain.value=1.5; lfo2.connect(lfo2G); lfo2.connect(padOscs[0].frequency); lfo2.start();
  const dur=4,n=a.sampleRate*dur,buf=a.createBuffer(1,n,a.sampleRate),d=buf.getChannelData(0); for(let i=0;i<n;i++)d[i]=(Math.random()*2-1); const ws=a.createBufferSource(); ws.buffer=buf; ws.loop=true; const wf=a.createBiquadFilter(); wf.type='bandpass'; wf.frequency.value=480; wf.Q.value=0.6; const wg=a.createGain(); wg.gain.value=0.04; ws.connect(wf).connect(wg).connect(master); ws.start();
  bgm={master,o1,o2,ws,padOscs,lfo,lfo2}; beat=0;
  bgmTimer=setInterval(()=>{ if(!bgm)return; const t=a.currentTime;
    const k=a.createOscillator(),kg=a.createGain(); k.type='sine'; k.frequency.setValueAtTime(92,t); k.frequency.exponentialRampToValueAtTime(40,t+0.18); kg.gain.setValueAtTime(0.0001,t); kg.gain.linearRampToValueAtTime(0.48,t+0.01); kg.gain.exponentialRampToValueAtTime(0.0008,t+0.42); k.connect(kg).connect(bgm.master); k.start(t); k.stop(t+0.46); beat++;
    if(beat%4===0){ const sub=a.createOscillator(),sg=a.createGain(); sub.type='sine'; sub.frequency.setValueAtTime(34,t); sub.frequency.exponentialRampToValueAtTime(26,t+1.2); sg.gain.setValueAtTime(0.0001,t); sg.gain.linearRampToValueAtTime(0.22,t+0.15); sg.gain.exponentialRampToValueAtTime(0.0006,t+1.6); sub.connect(sg).connect(bgm.master); sub.start(t); sub.stop(t+1.7); }
    if(beat%8===0)noise(.7,.10,240);
    if(Math.random()<0.12){ const al=a.createOscillator(),alg=a.createGain(),alf=a.createBiquadFilter(); al.type='sawtooth'; alf.type='lowpass'; alf.frequency.value=900; al.frequency.setValueAtTime(rnd(360,460),t); al.frequency.linearRampToValueAtTime(rnd(300,380),t+0.9); alg.gain.setValueAtTime(0.0001,t); alg.gain.linearRampToValueAtTime(0.05,t+0.4); alg.gain.exponentialRampToValueAtTime(0.0006,t+1.4); al.connect(alf).connect(alg).connect(bgm.master); al.start(t); al.stop(t+1.5); setTimeout(()=>noise(.18,.04,3200), rnd(200,600)); }
  }, 1300);
}

