  function roar(type){ const a=ensure(); if(!a)return; const t=a.currentTime;
    const P={ brute:{f0:58,dur:1.0,fmt:340,vibR:5.5,vibD:7,air:0.22,vol:0.34}, elite:{f0:82,dur:0.85,fmt:520,vibR:6,vibD:9,air:0.18,vol:0.30}, soldier:{f0:104,dur:0.72,fmt:680,vibR:6.5,vibD:11,air:0.16,vol:0.27}, runner:{f0:150,dur:0.62,fmt:920,vibR:8,vibD:16,air:0.20,vol:0.26} }[type] || {f0:104,dur:0.72,fmt:680,vibR:6.5,vibD:11,air:0.16,vol:0.27};
    const {f0,dur,fmt,vibR,vibD,air,vol}=P;
    const out=a.createGain(); out.gain.setValueAtTime(0.0001,t); out.gain.linearRampToValueAtTime(vol,t+0.06); out.gain.setValueAtTime(vol,t+dur*0.55); out.gain.exponentialRampToValueAtTime(0.0001,t+dur);
    const sh=a.createWaveShaper(); { const k=12,nn=256,c=new Float32Array(nn); for(let i=0;i<nn;i++){const x=i*2/nn-1; c[i]=(1+k)*x/(1+k*Math.abs(x));} sh.curve=c; sh.oversample='2x'; } out.connect(sh); sh.connect(a.destination);
    const o1=a.createOscillator(),o2=a.createOscillator(),og=a.createGain(); o1.type='sawtooth'; o2.type='sawtooth'; o1.frequency.setValueAtTime(f0,t); o1.frequency.linearRampToValueAtTime(f0*1.5,t+dur*0.7); o2.frequency.setValueAtTime(f0*1.01,t); o2.frequency.linearRampToValueAtTime(f0*1.5*1.01,t+dur*0.7); og.gain.value=0.9;
    const lfo=a.createOscillator(),lg=a.createGain(); lfo.type='sine'; lfo.frequency.setValueAtTime(vibR,t); lfo.frequency.linearRampToValueAtTime(vibR*1.8,t+dur); lg.gain.setValueAtTime(vibD,t); lg.gain.linearRampToValueAtTime(vibD*2.2,t+dur); lfo.connect(lg); lg.connect(o1.frequency); lg.connect(o2.frequency); lfo.start(t); lfo.stop(t+dur);
    const bp=a.createBiquadFilter(); bp.type='bandpass'; bp.Q.value=4.5; bp.frequency.setValueAtTime(fmt*0.7,t); bp.frequency.linearRampToValueAtTime(fmt*1.4,t+dur*0.6); o1.connect(og); o2.connect(og); og.connect(bp); bp.connect(out); o1.start(t); o2.start(t); o1.stop(t+dur); o2.stop(t+dur);
    const nN=Math.floor(a.sampleRate*dur),nb=a.createBuffer(1,nN,a.sampleRate),nd=nb.getChannelData(0); for(let i=0;i<nN;i++){const e=Math.min(1,i/(nN*0.08))*(1-i/nN); nd[i]=(Math.random()*2-1)*e;} const ns=a.createBufferSource(); ns.buffer=nb; const nf=a.createBiquadFilter(); nf.type='bandpass'; nf.Q.value=1.2; nf.frequency.setValueAtTime(fmt*1.2,t); nf.frequency.linearRampToValueAtTime(fmt*0.6,t+dur); const ng=a.createGain(); ng.gain.value=air; ns.connect(nf).connect(ng).connect(out); ns.start(t); ns.stop(t+dur);
  }

